        val encodedIv = Base64.encodeToString(iv, Base64.NO_WRAP)
        val encodedData = Base64.encodeToString(encryptedData, Base64.NO_WRAP)
        
        storeEncryptionKey(encodedKey)
        
        return "$encodedIv:$encodedData"
    }

